/**
 * Update payload for existing carriers.
 * Structured intelligence fields to merge into existing carrier objects.
 */
export interface CarrierUpdate {
  medicalConditions?: Carrier["medicalConditions"]
  combinationDeclines?: Carrier["combinationDeclines"]
  prescriptionExclusions?: Carrier["prescriptionExclusions"]
  livingBenefitsDetail?: Carrier["livingBenefitsDetail"]
  rateClassCriteria?: Carrier["rateClassCriteria"]
  sourceDocuments?: string[]
  availableAllStates?: boolean
  stateAvailabilityNotes?: string
  tobacco?: Carrier["tobacco"]
  additionalProducts?: Carrier["products"]
}

